const item = $input.first();
const json = item.json ?? {};
const binary = item.binary ?? {};

const from = typeof json.from === 'object'
  ? json.from.text || json.from.value?.[0]?.address || ''
  : (json.from || '');
const senderMatch = from.match(/<([^>]+)>/) || from.match(/([^\s<>]+@[^\s<>]+)/);
const sender = senderMatch ? senderMatch[1].trim().toLowerCase() : from.trim().toLowerCase();

const txId = String(json.messageId || json.messageID || json.uid || `${json.date || Date.now()}-${json.subject || 'email'}`);
const text = json.textPlain || json.text || json.bodyText || '';

const parts = [];

function fileNameOf(key, meta) {
  return String(meta.fileName || meta.fileNameDecoded || key);
}

function isPdfAttachment(key, meta) {
  return fileNameOf(key, meta).trim().toLowerCase().endsWith('.pdf');
}

if (String(text).trim().length > 0) {
  parts.push({
    filename: 'email-body.txt',
    mimeType: 'text/plain',
    data: Buffer.from(text).toString('base64'),
  });
}

for (const [key, meta] of Object.entries(binary)) {
  if (!isPdfAttachment(key, meta)) continue;
  const buffer = await this.helpers.getBinaryDataBuffer(0, key);
  parts.push({
    filename: fileNameOf(key, meta),
    mimeType: 'application/pdf',
    data: buffer.toString('base64'),
  });
}

if (parts.length === 0) return [];

const of = parts.length;
return parts.map((doc, i) => ({
  json: {
    txId,
    part: i + 1,
    of,
    sender,
    document: doc,
  },
}));

return $input.all().map((item) => ({
  json: {
    tripcalUrl: 'https://ralfw-tripstar.netlify.app/api/ingest-email',
    tripcalToken: 'c423b7d9-70d0-43c1-831e-7d6fd843e1b1',
    payload: item.json,
  },
}));

const responses = $input.all();
const configs = $('TripCal Config').all();
const failures = [];

for (let index = 0; index < responses.length; index += 1) {
  const response = responses[index].json ?? {};
  if (!response.error) continue;

  const config = configs[index]?.json ?? configs[0]?.json ?? {};
  const payload = config.payload ?? {};
  const error = response.error;

  failures.push({
    json: {
      sender: payload.sender || '',
      txId: payload.txId || '',
      filename: payload.document?.filename || null,
      endpoint: config.tripcalUrl,
      httpStatus: error.httpCode || error.statusCode || error.status || error.code || 'request_error',
      httpStatusText: error.message || error.name || 'TripStar request failed',
      responseBody: error.description || error.response?.body || error.stack || JSON.stringify(error),
    },
  });
}

return failures;

const item = $input.first();
const sender = item.json.sender || '';

const body = [
  'TripStar konnte eine weitergeleitete E-Mail nicht verarbeiten.',
  '',
  `Von: ${sender}`,
  `TripStar Endpoint: ${item.json.endpoint}`,
  '',
  `HTTP Status: ${item.json.httpStatus} ${item.json.httpStatusText || ''}`.trim(),
  '',
  'Antwort der TripStar API:',
  item.json.responseBody || '(keine Antwort)',
  '',
  item.json.filename ? `Dokument: ${item.json.filename}` : '',
].filter((line) => line !== '').join('\n');

return [
  {
    json: {
      toEmail: sender,
      fromEmail: 'tripcal-documents@work-with-ease.eu',
      subject: 'TripStar Fehler: Email-Ingest',
      text: body,
      headers: '',
    },
  },
];

